package com.example.grpc.debugerror;

import com.google.protobuf.Any;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import com.google.rpc.Status;
import io.grpc.protobuf.StatusProto;
import io.grpc.stub.StreamObserver;

import java.io.PrintWriter;
import java.io.StringWriter;
import java.sql.SQLException;
import java.util.UUID;

public class DebugErrorServiceImpl extends DebugErrorServiceGrpc.DebugErrorServiceImplBase {

    @Override
    public void performOperation(OperationRequest request, StreamObserver<OperationResponse> responseObserver) {
        try {
            if (request.getShouldFailDb()) {
                // Simulate a database error
                throw new SQLException("Simulated database connection lost or query failed for: " + request.getInputData());
            }
            if (request.getShouldFailInternal()) {
                // Simulate an internal application error (e.g., invalid input logic)
                throw new IllegalArgumentException("Invalid input data provided, cannot process: " + request.getInputData());
            }

            // Simulate some successful processing
            String result = "Processed: " + request.getInputData() + " successfully at " + System.currentTimeMillis();
            responseObserver.onNext(OperationResponse.newBuilder().setOutputData(result).build());
            responseObserver.onCompleted();

        } catch (Exception e) {
            // Start building com.google.rpc.Status object
            Status.Builder statusBuilder = Status.newBuilder();

            // Default to INTERNAL error if not specifically handled
            io.grpc.Status.Code grpcStatusCode = io.grpc.Status.Code.INTERNAL;
            String mainErrorMessage = "An unexpected error occurred.";

            if (e instanceof SQLException) {
                grpcStatusCode = io.grpc.Status.Code.UNAVAILABLE; // Reflects a database issue
                mainErrorMessage = "Database error occurred: " + e.getMessage();
                statusBuilder.setCode(com.google.rpc.Code.UNAVAILABLE.getNumber());
                statusBuilder.setMessage(mainErrorMessage);

                // Add ErrorInfo for database-specific details and internal state
                ErrorInfo dbErrorInfo = ErrorInfo.newBuilder()
                        .setReason("DATABASE_FAILURE")
                        .setDomain("com.example.app.database")
                        .putMetadata("db_error_code", "SQL-23502") // Example SQLSTATE or custom code
                        .putMetadata("db_connection_id", "conn-" + UUID.randomUUID().toString().substring(0, 8)) // Simulated DB connection ID
                        .putMetadata("attempted_query_fragment", "SELECT * FROM users WHERE...") // Part of the query that failed
                        .putMetadata("service_context", "user_data_retrieval")
                        .build();
                statusBuilder.addDetails(Any.pack(dbErrorInfo));

            } else if (e instanceof IllegalArgumentException) {
                grpcStatusCode = io.grpc.Status.Code.INVALID_ARGUMENT; // Reflects bad input
                mainErrorMessage = "Input validation failed: " + e.getMessage();
                statusBuilder.setCode(com.google.rpc.Code.INVALID_ARGUMENT.getNumber());
                statusBuilder.setMessage(mainErrorMessage);

                // Add ErrorInfo for internal state/validation details
                ErrorInfo validationErrorInfo = ErrorInfo.newBuilder()
                        .setReason("INVALID_INPUT_DATA")
                        .setDomain("com.example.app.validation")
                        .putMetadata("requested_input", request.getInputData()) // The problematic input
                        .putMetadata("validation_rule_violated", "data_cannot_contain_special_chars")
                        .putMetadata("internal_processor_id", "PROC-1A2B3C") // Another example internal state
                        .putMetadata("user_id_context", "debugger_user_123") // Context about who made the request
                        .build();
                statusBuilder.addDetails(Any.pack(validationErrorInfo));

            } else {
                // Generic unexpected internal error
                mainErrorMessage = "Internal server error: " + e.getMessage();
                statusBuilder.setCode(com.google.rpc.Code.INTERNAL.getNumber());
                statusBuilder.setMessage(mainErrorMessage);

                // Add some generic error info for unexpected errors
                ErrorInfo genericErrorInfo = ErrorInfo.newBuilder()
                        .setReason("UNEXPECTED_EXCEPTION")
                        .setDomain("com.example.app.general")
                        .putMetadata("error_instance_id", UUID.randomUUID().toString())
                        .putMetadata("thread_name", Thread.currentThread().getName())
                        .putMetadata("component", "PerformOperationService")
                        .build();
                statusBuilder.addDetails(Any.pack(genericErrorInfo));
            }

            // Always add DebugInfo with full stack trace for any exception for detailed debugging
            StringWriter sw = new StringWriter();
            e.printStackTrace(new PrintWriter(sw));
            String stackTrace = sw.toString();

            DebugInfo debugInfo = DebugInfo.newBuilder()
                    .addStackTraces(stackTrace)
                    .setDetail("Exception Type: " + e.getClass().getName() + "\nRoot Cause Message: " + e.getMessage())
                    .build();
            statusBuilder.addDetails(Any.pack(debugInfo));

            // Create and throw StatusRuntimeException using StatusProto.toStatusRuntimeException
            // This utility converts com.google.rpc.Status protobuf into an io.grpc.Status and wraps it.
            // The main message from StatusProto.toStatusRuntimeException will be the 'description' of the gRPC Status.
            responseObserver.onError(StatusProto.toStatusRuntimeException(statusBuilder.build()));
        }
    }
}


// src/main/java/com/example/grpc/debugerror/DebugErrorServer.java
package com.example.grpc.debugerror;

import io.grpc.Server;
import io.grpc.ServerBuilder;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

public class DebugErrorServer {
    private final int port;
    private final Server server;

    public DebugErrorServer(int port) {
        this.port = port;
        this.server = ServerBuilder.forPort(port)
                .addService(new DebugErrorServiceImpl())
                .build();
    }

    public void start() throws IOException {
        server.start();
        System.out.println("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            // Use stderr here since the logger may have been reset by its JVM shutdown hook.
            System.err.println("*** shutting down gRPC server since JVM is shutting down");
            try {
                DebugErrorServer.this.stop();
            } catch (InterruptedException e) {
                e.printStackTrace(System.err);
            }
            System.err.println("*** server shut down");
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    /**
     * Await termination on the main thread since the grpc library uses daemon threads.
     */
    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        DebugErrorServer server = new DebugErrorServer(50051);
        server.start();
        server.blockUntilShutdown();
    }
}


