package com.example.grpc.debugerror;

import com.google.protobuf.Any;
import com.google.protobuf.InvalidProtocolBufferException;
import com.google.rpc.DebugInfo;
import com.google.rpc.ErrorInfo;
import com.google.rpc.Status;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.util.concurrent.TimeUnit;

public class DebugErrorClient {
    private final ManagedChannel channel;
    private final DebugErrorServiceGrpc.DebugErrorServiceBlockingStub blockingStub;

    public DebugErrorClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .build();
        blockingStub = DebugErrorServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void performOperation(String inputData, boolean shouldFailDb, boolean shouldFailInternal) {
        OperationRequest request = OperationRequest.newBuilder()
                .setInputData(inputData)
                .setShouldFailDb(shouldFailDb)
                .setShouldFailInternal(shouldFailInternal)
                .build();

        System.out.println("\n--- Attempting Operation with input: '" + inputData +
                "', shouldFailDb: " + shouldFailDb + ", shouldFailInternal: " + shouldFailInternal + " ---");

        try {
            OperationResponse response = blockingStub.performOperation(request);
            System.out.println("Operation Succeeded: " + response.getOutputData());
        } catch (StatusRuntimeException e) {
            System.err.println("Operation Failed! gRPC Status: " + e.getStatus().getCode() +
                               " - " + e.getStatus().getDescription());

            // Extract the com.google.rpc.Status protobuf from the StatusRuntimeException
            Status status = StatusProto.fromThrowable(e);
            if (status != null) {
                System.err.println("  Detailed com.google.rpc.Status information:");
                System.err.println("    Code: " + status.getCode());
                System.err.println("    Message: " + status.getMessage());

                for (Any detail : status.getDetailsList()) {
                    try {
                        if (detail.is(DebugInfo.class)) {
                            DebugInfo debugInfo = detail.unpack(DebugInfo.class);
                            System.err.println("    [DebugInfo]");
                            System.err.println("      Detail: " + debugInfo.getDetail());
                            for (String stackTrace : debugInfo.getStackTracesList()) {
                                System.err.println("      Stack Trace:\n" + stackTrace.indent(8)); // Indent for readability
                            }
                        } else if (detail.is(ErrorInfo.class)) {
                            ErrorInfo errorInfo = detail.unpack(ErrorInfo.class);
                            System.err.println("    [ErrorInfo]");
                            System.err.println("      Reason: " + errorInfo.getReason());
                            System.err.println("      Domain: " + errorInfo.getDomain());
                            System.err.println("      Metadata: " + errorInfo.getMetadataMap());
                        } else {
                            System.err.println("    [Unknown Detail Type]: " + detail.getTypeUrl());
                        }
                    } catch (InvalidProtocolBufferException protoEx) {
                        System.err.println("    Failed to unpack detail of type " + detail.getTypeUrl() + ": " + protoEx.getMessage());
                    }
                }
            } else {
                System.err.println("  No com.google.rpc.Status details found in the exception.");
            }
        }
    }

    public static void main(String[] args) throws InterruptedException {
        DebugErrorClient client = new DebugErrorClient("localhost", 50051);
        try {
            // Successful call
            client.performOperation("valid_data_123", false, false);

            // Simulate database error
            client.performOperation("data_for_db_failure", true, false);

            // Simulate internal application error
            client.performOperation("invalid_format_xyz", false, true);

            // Simulate generic internal error (if logic could lead to other exceptions)
            // For this example, only DB and IllegalArgument are explicitly simulated.
            // A third catch block for general Exception might hit this.
            // Let's force an unexpected error by simulating null pointer for example.
            // This would require a modification to DebugErrorServiceImpl to throw a different Exception.
            // For now, the IllegalArgumentException will serve as a general app error for demonstration.

        } finally {
            client.shutdown();
        }
    }
}